namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 4, Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on CS pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, CourseCode = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research focuses on algorithm optimization and competitive programming.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, CourseCode = "CS310", Title = "Database Systems", Description = "Design and implementation of relational databases, SQL, normalization, transaction processing, and query optimization.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked in industry for 10 years before joining academia, specializing in distributed databases.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with expertise in real analysis.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and computer graphics.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson researches applications of linear algebra in machine learning.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist who brings hands-on demonstrations to every lecture.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 7, CourseCode = "PHYS220", Title = "Quantum Mechanics", Description = "Introduction to wave functions, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research in quantum computing bridges physics and computer science.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 8, CourseCode = "ENG110", Title = "Academic Writing", Description = "Develop skills in argumentative writing, research methods, and critical reading for academic contexts.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. David Moore", InstructorBio = "Prof. Moore has authored three books on rhetoric and composition pedagogy.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, CourseCode = "ENG250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Lisa Hernandez", InstructorBio = "Dr. Hernandez specializes in 20th-century American fiction and has been a Fulbright scholar.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, CourseCode = "HIST101", Title = "World History to 1500", Description = "Survey of major civilizations, cultural exchanges, and historical developments from prehistory to 1500 CE.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Michael Okafor", InstructorBio = "Dr. Okafor is an expert in ancient trade networks and cross-cultural interactions.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 11, CourseCode = "HIST230", Title = "Modern European History", Description = "Political, social, and cultural developments in Europe from the Enlightenment to the present.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. Anna Petrov", InstructorBio = "Dr. Petrov researches the intellectual history of modern Europe with a focus on political thought.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

