arguments.file_text:
@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor…" />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(Model.CourseId)?.Title)</strong> has been received.</p>
        <a href="/courses" class="btn btn-primary">Back to Catalog</a>
    </div>
}
else
{
    <form method="post" action="/enroll" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <input type="text" id="fullName" name="Model.FullName" value="@Model.FullName" class="form-control" required />
            @if (errors.ContainsKey(nameof(Model.FullName)))
            {
                <div class="text-danger">@errors[nameof(Model.FullName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" placeholder="e.g. ABC12345" required />
            @if (errors.ContainsKey(nameof(Model.StudentId)))
            {
                <div class="text-danger">@errors[nameof(Model.StudentId)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode — @course.Title</option>
                }
            </select>
            @if (errors.ContainsKey(nameof(Model.CourseId)))
            {
                <div class="text-danger">@errors[nameof(Model.CourseId)]</div>
            }
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private Dictionary<string, string> errors = new();
    private bool Submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        // Pre-select course if passed via query string and form hasn't been posted
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        // Validate on POST
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? "GET"))
        {
            var context = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
            var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
            if (System.ComponentModel.DataAnnotations.Validator.TryValidateObject(Model, context, results, true))
            {
                Submitted = true;
            }
            else
            {
                foreach (var result in results)
                {
                    foreach (var member in result.MemberNames)
                    {
                        errors.TryAdd(member, result.ErrorMessage ?? "Invalid");
                    }
                }
            }
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }
}

